/* ============================================================
   THE BRASS LANTERN – PUB TRIVIA  |  questions.js
   ============================================================
   HOW TO ADD QUESTIONS
   Each question object must have:
     id          – unique number
     category    – must match one of the 12 category strings exactly (see list below)
     difficulty  – "easy", "medium", or "hard"
     question    – the question text (string)
     options     – array of exactly 4 strings: ["A text","B text","C text","D text"]
     answer      – index (0–3) of the correct option in the options array
     fun_fact    – short interesting fact shown after the answer is revealed

   VALID CATEGORY STRINGS:
     "History"               "Science & Nature"    "Geography"
     "Movies & TV"           "Music"               "Sports"
     "Food & Drink"          "Literature"          "Technology"
     "Pop Culture"           "Art & Design"        "Mythology & Religion"

   EXAMPLE:
   {
     id: 999,
     category: "History",
     difficulty: "medium",
     question: "In which year did World War II end?",
     options: ["1943", "1944", "1945", "1946"],
     answer: 2,
     fun_fact: "VJ Day (Victory over Japan) on 15 August 1945 marked the effective end of the war."
   },
   ============================================================ */

